import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestions: CareerQuestion[] = [
  { id: "pta-001", stem: "A patient is 3 days post posterior approach total hip replacement. Which position must be AVOIDED?", options: ["Hip abduction with pillow between legs", "Hip flexion to 70° during seated activities", "Hip flexion >90° with internal rotation and adduction", "Ankle dorsiflexion exercises in supine"], correctIndex: 2, rationale: "Posterior approach THR precautions: no hip flexion >90°, no adduction past midline, no internal rotation. These combined movements risk posterior dislocation of the prosthesis.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-002", stem: "A patient is non-weight-bearing on the left lower extremity. Which gait pattern with axillary crutches is appropriate?", options: ["4-point alternating gait", "2-point alternating gait", "3-point gait pattern", "Swing-to pattern without crutches"], correctIndex: 2, rationale: "The 3-point gait pattern is used for NWB: both crutches advance with the affected limb (no weight on it), then the unaffected limb steps through independently.", difficulty: 2, category: "Clinical Scenarios", topic: "Assistive Devices" },
  { id: "pta-003", stem: "Using the DeLorme PRE protocol, a patient's 10RM is 30 pounds. What resistance is used for Set 2?", options: ["10 pounds", "15 pounds", "22.5 pounds (75% of 10RM)", "30 pounds"], correctIndex: 2, rationale: "DeLorme PRE: Set 1 = 50% of 10RM (15 lbs), Set 2 = 75% of 10RM (22.5 lbs), Set 3 = 100% of 10RM (30 lbs). The protocol uses ascending resistance.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-004", stem: "A patient with T6 SCI suddenly develops severe headache, hypertension (BP 220/130), and flushing above the injury level. What should the PTA do FIRST?", options: ["Continue treatment to maintain cardiovascular fitness", "Position the patient supine and elevate legs", "Sit the patient upright immediately and check for noxious stimuli", "Administer prescribed antihypertensive medication"], correctIndex: 2, rationale: "These symptoms indicate autonomic dysreflexia — a life-threatening emergency. Sit the patient upright (lowers BP), check for noxious stimuli (kinked catheter, tight clothing), and notify medical team.", difficulty: 3, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-005", stem: "A patient scores 38 on the Berg Balance Scale. What does this score indicate?", options: ["Normal balance with no intervention needed", "Fall risk — patient requires assistive device and balance intervention", "Wheelchair-bound — unable to ambulate", "Superior balance function"], correctIndex: 1, rationale: "BBS <45 indicates fall risk; <36 indicates high fall risk. A score of 38 suggests the patient needs an assistive device and a balance training program.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-006", stem: "Where should the axillary crutch pad be positioned relative to the axilla?", options: ["Firmly pressed into the axilla for support", "2-3 finger widths below the axilla", "At the level of the shoulder", "4-5 inches below the axilla"], correctIndex: 1, rationale: "The pad should be 2-3 finger widths below the axilla. Weight is borne through the hands, not the axillary pads, to prevent radial nerve compression (crutch palsy).", difficulty: 1, category: "Safety", topic: "Assistive Devices" },
  { id: "pta-007", stem: "A patient with right hemiplegia needs to transfer from wheelchair to bed. Where should the wheelchair be positioned?", options: ["On the patient's right (affected) side", "On the patient's left (unaffected) side", "Directly facing the bed", "At the foot of the bed"], correctIndex: 1, rationale: "Position the wheelchair on the unaffected (left) side. The patient leads the stand-pivot transfer with the stronger left leg, providing stability during the pivot.", difficulty: 2, category: "Patient Care Planning", topic: "Patient Mobility Techniques" },
  { id: "pta-008", stem: "A patient reports an RPE of 17 on the Borg scale during aerobic exercise. What is the appropriate PTA action?", options: ["Increase intensity for greater training effect", "Maintain current intensity as this is appropriate", "Decrease intensity — RPE 17 exceeds the moderate training zone", "Stop exercise immediately and call emergency services"], correctIndex: 2, rationale: "RPE 17 ('very hard') exceeds the target moderate intensity range (12-14). The PTA should reduce intensity to return the patient to the prescribed exertion level.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-009", stem: "Which orthopedic special test assesses the integrity of the ACL?", options: ["McMurray test", "Phalen test", "Lachman test", "Thompson test"], correctIndex: 2, rationale: "The Lachman test assesses ACL integrity by applying anterior tibial force at 20-30° knee flexion. A positive test shows excessive anterior translation with a soft/absent endpoint.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-010", stem: "A patient is 6 weeks post-ACL reconstruction. Which exercise is CONTRAINDICATED?", options: ["Closed kinetic chain squats to 60°", "Stationary cycling", "Open kinetic chain knee extension from 45° to 0°", "Straight leg raises"], correctIndex: 2, rationale: "OKC knee extension through 45-0° places excessive anterior shear force on the healing ACL graft. CKC exercises are preferred because they create protective posterior tibial translation.", difficulty: 3, category: "Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-011", stem: "A 13-month-old child has not yet started walking. Is this a concern?", options: ["Yes, walking should begin by 9 months", "No, independent walking typically develops between 12-15 months", "Yes, the child needs immediate surgical intervention", "No, walking is not expected until age 3"], correctIndex: 1, rationale: "Independent walking typically develops between 12-15 months. At 13 months, the child is within the normal developmental window and may not yet be developmentally ready.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-012", stem: "A patient using a cane for right knee pain should hold the cane in which hand?", options: ["Right hand (same side as pain)", "Left hand (opposite side of pain)", "Either hand based on personal preference", "Alternating hands every 10 steps"], correctIndex: 1, rationale: "The cane is held on the opposite side of the affected LE. This creates a wider base of support and counterbalances forces to reduce load on the painful side.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-013", stem: "During gait observation, a patient demonstrates lateral trunk lean over the right leg during right stance phase. Which muscle is likely weak?", options: ["Right quadriceps", "Right gluteus medius", "Right hamstrings", "Right tibialis anterior"], correctIndex: 1, rationale: "Lateral trunk lean toward the stance leg (compensated Trendelenburg) indicates gluteus medius weakness. The trunk lean shifts the center of gravity over the stance leg to compensate.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-014", stem: "Which type of muscle contraction generates force WITHOUT joint movement?", options: ["Concentric isotonic", "Eccentric isotonic", "Isometric", "Isokinetic"], correctIndex: 2, rationale: "Isometric contraction produces muscle force without joint movement or change in muscle length. It is used when joint motion is contraindicated, such as during immobilization.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-015", stem: "A patient has a Timed Up and Go (TUG) score of 22 seconds. What does this indicate?", options: ["Normal mobility for all ages", "Freely mobile without limitations", "Variable mobility with increased fall risk", "Complete independence in all mobility tasks"], correctIndex: 2, rationale: "TUG 20-30 seconds indicates variable mobility. The patient may require an assistive device and has increased fall risk. Further balance and gait assessment is warranted.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-016", stem: "A patient is performing a sliding board transfer. What is the MOST important safety check before the transfer?", options: ["Check that the patient is wearing proper footwear", "Lock wheelchair brakes, remove armrest, and position the board correctly", "Ensure the room temperature is comfortable", "Check that the bed is made properly"], correctIndex: 1, rationale: "Before a sliding board transfer, wheelchair brakes must be locked, the near armrest removed, and the board properly positioned bridging both surfaces to prevent falls.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-017", stem: "Which PNF diagonal pattern involves upper extremity flexion, adduction, and external rotation?", options: ["D1 flexion", "D1 extension", "D2 flexion", "D2 extension"], correctIndex: 0, rationale: "D1 flexion: flexion, adduction, external rotation with forearm supination. This mimics reaching across the body to the opposite shoulder.", difficulty: 3, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-018", stem: "A 75-year-old patient with osteoporosis asks about safe exercises. Which should the PTA AVOID recommending?", options: ["Walking program", "Standing hip extension exercises", "Seated trunk flexion (crunches/sit-ups)", "Standing posture exercises emphasizing extension"], correctIndex: 2, rationale: "Spinal flexion exercises increase compressive forces on anterior vertebral bodies, increasing fracture risk in osteoporosis. Weight-bearing and extension exercises are preferred.", difficulty: 2, category: "Safety", topic: "Geriatric Rehabilitation" },
  { id: "pta-019", stem: "What is the PRIMARY role of the PTA in patient care?", options: ["Perform initial evaluations and establish physical therapy diagnoses", "Implement interventions within the PT-established plan of care", "Independently modify the plan of care and discharge patients", "Prescribe medications for pain management"], correctIndex: 1, rationale: "The PTA implements interventions within the plan of care established by the supervising PT. Initial evaluation, diagnosis, prognosis, and discharge decisions are PT responsibilities.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-020", stem: "A patient is performing static stretching of the hamstrings. How long should the stretch be held for optimal gains?", options: ["5 seconds", "10 seconds", "30 seconds", "5 minutes"], correctIndex: 2, rationale: "Research supports holding static stretches for 30 seconds for optimal flexibility gains. No significant additional benefit has been shown beyond 30-second holds in most populations.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-021", stem: "A patient with spastic diplegic cerebral palsy is classified as GMFCS Level III. What does this indicate?", options: ["Walks without limitations", "Walks with limitations but no device needed", "Walks using a handheld mobility device", "Requires powered wheelchair for all mobility"], correctIndex: 2, rationale: "GMFCS Level III: walks using a handheld mobility device (walker, crutches). May use wheeled mobility for longer distances or uneven terrain.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-022", stem: "The PTA is measuring shoulder flexion ROM using a goniometer. The axis of the goniometer should be placed at which anatomical landmark?", options: ["Lateral epicondyle of the humerus", "Acromion process", "Olecranon process", "Coracoid process"], correctIndex: 1, rationale: "For shoulder flexion goniometry, the axis is placed at the acromion process, the stationary arm aligns with the midaxillary line, and the moving arm with the lateral humerus.", difficulty: 2, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-023", stem: "A patient's systolic blood pressure rises to 260 mmHg during exercise. What is the appropriate PTA action?", options: ["Continue exercise at a reduced pace", "Stop exercise immediately and monitor the patient", "Increase exercise intensity to improve cardiovascular fitness", "Have the patient perform relaxation breathing and continue"], correctIndex: 1, rationale: "Exercise should be stopped immediately if SBP exceeds 250 mmHg or DBP exceeds 115 mmHg. These values indicate dangerous hypertensive response requiring medical attention.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-024", stem: "A patient with a 3-month-old right torticollis is referred for PT. Which muscle is tight?", options: ["Left sternocleidomastoid", "Right sternocleidomastoid", "Bilateral upper trapezius", "Left scalene"], correctIndex: 1, rationale: "In right torticollis, the right SCM is tight, causing head tilt toward the right and chin rotation toward the left. Treatment stretches the right SCM and strengthens the left.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-025", stem: "Which gait pattern with crutches is the MOST stable?", options: ["Swing-through", "2-point alternating", "4-point alternating", "3-point"], correctIndex: 2, rationale: "The 4-point alternating gait (right crutch → left foot → left crutch → right foot) is the most stable because 3 points of contact are always on the ground.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-026", stem: "During stair training, a patient with right knee injury using crutches should go UP stairs leading with which leg?", options: ["Right (affected) leg first", "Left (unaffected) leg first", "Both legs simultaneously", "Either leg — it doesn't matter"], correctIndex: 1, rationale: "'Up with the good' — the unaffected (left) leg leads going up stairs, pushing the body weight up with the stronger leg. Then the crutches and affected leg follow.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-027", stem: "A patient recovering from stroke is in Brunnstrom Stage 4 of motor recovery. What characterizes this stage?", options: ["Complete flaccidity", "Movement only within synergy patterns", "Voluntary movement begins to emerge outside of synergy", "Near-normal motor control"], correctIndex: 2, rationale: "Brunnstrom Stage 4 marks the beginning of voluntary movement outside stereotypical synergy patterns. The patient can initiate some isolated movements with decreased synergy influence.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-028", stem: "A patient with moderate spasticity scores 2 on the Modified Ashworth Scale. What does this mean?", options: ["No increase in muscle tone", "Marked increase in tone through most of the ROM, but the limb is easily moved", "Considerable increase in tone; passive movement is difficult", "Limb is rigid in flexion or extension"], correctIndex: 1, rationale: "MAS 2: marked increase in muscle tone through most of the ROM, but the affected part is still easily moved passively. Higher scores (3-4) indicate greater resistance to passive movement.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-029", stem: "How should the PTA grasp the gait belt during an assisted transfer?", options: ["From the top with palms facing down", "From underneath with palms facing up", "By the buckle only", "By the patient's clothing instead of the belt"], correctIndex: 1, rationale: "The gait belt is grasped from underneath with palms up. This grip provides optimal control and leverage to safely guide the patient downward if they begin to fall.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-030", stem: "A patient is 2 weeks post-rotator cuff repair. Which exercise is appropriate?", options: ["Active shoulder elevation to 180°", "Passive ROM within surgeon's protocol", "Resistive shoulder strengthening with weights", "Overhead throwing exercises"], correctIndex: 1, rationale: "At 2 weeks post-rotator cuff repair, only passive ROM within the surgeon's protocol is appropriate. Active shoulder motion is typically restricted for 6 weeks to protect the repair.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-031", stem: "The 30-second chair stand test result for an older adult is 6 repetitions. What does this indicate?", options: ["Excellent lower extremity strength", "Normal functional strength for older adults", "Below normal — indicates fall risk (fewer than 8 = fall risk)", "Superior performance requiring no intervention"], correctIndex: 2, rationale: "Fewer than 8 chair stands in 30 seconds indicates functional lower extremity weakness and increased fall risk in older adults. Strengthening intervention is warranted.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-032", stem: "Which therapeutic modality uses sound waves to produce deep tissue heating?", options: ["TENS", "Cryotherapy", "Therapeutic ultrasound", "Moist hot packs"], correctIndex: 2, rationale: "Therapeutic ultrasound uses high-frequency sound waves to produce deep tissue heating (thermal effects at continuous mode) and promote tissue healing (non-thermal effects at pulsed mode).", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-033", stem: "A patient with Parkinson's disease demonstrates a shuffling, festinating gait. Which intervention is MOST appropriate?", options: ["Leg weights to slow the gait speed", "External auditory cues (metronome) and visual cues (floor lines) to improve step length", "Walking backward exclusively", "Restricting all ambulation to prevent falls"], correctIndex: 1, rationale: "External cues (auditory rhythmic cues and visual targets) help patients with Parkinson's overcome akinesia and improve step length, cadence, and gait quality.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-034", stem: "Which weight-bearing status means the patient can put ONLY the toe on the ground for balance, not for support?", options: ["Non-weight-bearing (NWB)", "Toe-touch weight-bearing (TTWB)", "Partial weight-bearing (PWB)", "Full weight-bearing (FWB)"], correctIndex: 1, rationale: "TTWB allows only toe contact with the floor for balance — no actual weight transfer through the affected extremity. It provides tactile feedback without structural loading.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-035", stem: "A patient with SCI at C5 level can be expected to achieve which functional activity?", options: ["Independent ambulation", "Self-feeding with adaptive equipment and setup assistance", "Independent transfers without equipment", "Independent wheelchair propulsion on all surfaces"], correctIndex: 1, rationale: "C5 SCI preserves deltoid and biceps. With mobile arm supports and adaptive equipment (universal cuff), the patient can self-feed with setup but requires assistance for most other activities.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-036", stem: "During balance training, which progression sequence correctly increases challenge?", options: ["Dynamic → Static → Eyes closed → Unstable surface", "Stable surface/eyes open → Stable surface/eyes closed → Unstable surface/eyes open → Unstable surface/eyes closed", "Single-leg stance → Bilateral stance → Sitting balance", "Unstable surface first → Add support last"], correctIndex: 1, rationale: "Balance training progresses by systematically removing sensory input and reducing base stability: stable/eyes open → stable/eyes closed → unstable/eyes open → unstable/eyes closed.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-037", stem: "A child with cerebral palsy receives botulinum toxin injection to the gastrocnemius. What should the PTA do during the 'window' of reduced tone?", options: ["Rest the muscle completely for 3 months", "Intensify stretching, strengthening, and functional training while tone is reduced", "Discontinue physical therapy until the injection wears off", "Apply ice to the injection site daily"], correctIndex: 1, rationale: "Botox effects last 3-6 months. The PTA should capitalize on reduced spasticity by intensifying stretching, strengthening, and functional gait training during this therapeutic window.", difficulty: 3, category: "Therapeutic Intervention", topic: "Pediatric Rehabilitation" },
  { id: "pta-038", stem: "The Thompson test is used to assess the integrity of which structure?", options: ["Anterior cruciate ligament", "Meniscus", "Achilles tendon", "Rotator cuff"], correctIndex: 2, rationale: "The Thompson test (calf squeeze test) assesses Achilles tendon integrity. Squeezing the calf should produce plantar flexion; absence of plantar flexion indicates Achilles tendon rupture.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-039", stem: "A patient with COPD is performing aerobic exercise. Which monitoring tool should the PTA use to assess exertion intensity?", options: ["Glasgow Coma Scale", "Borg Rating of Perceived Exertion (RPE) scale", "Allen Cognitive Level Screen", "Modified Ashworth Scale"], correctIndex: 1, rationale: "The Borg RPE scale (6-20) allows patients to self-report exercise intensity. Target moderate intensity is RPE 12-14 ('somewhat hard'). It correlates approximately with HR ÷ 10.", difficulty: 1, category: "Patient Care Planning", topic: "Therapeutic Exercise" },
  { id: "pta-040", stem: "How often should a wheelchair-bound patient perform pressure-relieving weight shifts?", options: ["Once per hour", "Every 15-30 minutes", "Once per day", "Only when experiencing pain"], correctIndex: 1, rationale: "Weight shifts every 15-30 minutes redistribute pressure over bony prominences (ischial tuberosities) to prevent pressure injuries. Methods include forward lean, side lean, and push-ups.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-041", stem: "Which gait deviation indicates dorsiflexor weakness?", options: ["Trendelenburg gait", "Steppage gait (high stepping)", "Antalgic gait", "Vaulting gait"], correctIndex: 1, rationale: "Steppage gait involves excessive hip and knee flexion during swing phase to clear the foot from the floor. It results from dorsiflexor weakness (foot drop) — tibialis anterior dysfunction.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-042", stem: "A patient is performing closed kinetic chain exercises for knee rehabilitation. Which exercise is an example of CKC?", options: ["Seated knee extension with ankle weight", "Standing mini-squats", "Prone hamstring curls", "Supine leg lifts"], correctIndex: 1, rationale: "CKC exercises have the distal segment (foot) fixed. Standing mini-squats fix the foot on the ground, creating co-contraction and joint compression that protect the ACL graft.", difficulty: 1, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-043", stem: "A patient presents with positive Phalen's and Tinel's tests. Which condition do these tests suggest?", options: ["ACL tear", "Achilles tendon rupture", "Carpal tunnel syndrome", "Rotator cuff tear"], correctIndex: 2, rationale: "Phalen's (sustained wrist flexion reproduces symptoms) and Tinel's (tapping over carpal tunnel reproduces symptoms) are clinical tests for carpal tunnel syndrome (median nerve compression).", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-044", stem: "The PTA is providing gait training to a patient using a standard walker. What is the correct gait sequence?", options: ["Step with both feet, then advance the walker", "Advance the walker, then step with one foot, then the other", "Run toward the walker after placing it", "Advance the walker and hop to it with both feet"], correctIndex: 1, rationale: "Standard walker gait: advance the walker forward, then step with one foot (typically affected foot first), then step with the other foot. The walker provides support during each step.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-045", stem: "A patient with osteoporosis has a T-score of -3.0 on DEXA scan. What does this indicate?", options: ["Normal bone density", "Osteopenia", "Osteoporosis", "Above-average bone density"], correctIndex: 2, rationale: "DEXA T-scores: >-1.0 = normal; -1.0 to -2.5 = osteopenia; ≤-2.5 = osteoporosis. A T-score of -3.0 indicates established osteoporosis with significant fracture risk.", difficulty: 2, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-046", stem: "During manual muscle testing, a patient can move their knee through full ROM against gravity but cannot tolerate any manual resistance. What is the MMT grade?", options: ["2/5 (Poor)", "3/5 (Fair)", "4/5 (Good)", "5/5 (Normal)"], correctIndex: 1, rationale: "MMT 3/5 (Fair): the patient can move the joint through full available ROM against gravity but cannot hold against any additional manual resistance.", difficulty: 1, category: "Clinical Scenarios", topic: "Therapeutic Exercise" },
  { id: "pta-047", stem: "A patient with heart failure is beginning a cardiac rehabilitation program. Which MET level activity is appropriate for the initial phase?", options: ["1-2 METs (self-care, slow walking)", "5-6 METs (brisk walking, cycling)", "8-10 METs (running, competitive sports)", "12+ METs (sprint activities)"], correctIndex: 0, rationale: "Initial cardiac rehabilitation starts at 1-2 METs (self-care activities, slow walking). Intensity is gradually progressed based on patient tolerance, vital signs, and symptoms.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-048", stem: "What is the primary advantage of using a rolling walker compared to a standard pick-up walker?", options: ["It provides more stability", "It allows a reciprocal gait pattern with continuous forward motion", "It is less expensive", "It is lighter weight"], correctIndex: 1, rationale: "A rolling walker (wheeled walker) allows continuous forward motion and a more normal reciprocal gait pattern, whereas a standard walker requires stopping to lift and advance.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-049", stem: "A patient is performing PNF contract-relax stretching for tight hamstrings. What is the correct sequence?", options: ["Passive stretch → Active contraction of tight muscle → Relax → Passive stretch into new range", "Contract agonist → Stretch agonist → Contract antagonist", "Ballistic bouncing into end range", "Forceful passive stretch without contraction"], correctIndex: 0, rationale: "Contract-relax PNF: passive stretch to end range → patient contracts the tight muscle (hamstring) isometrically → relax → therapist moves the limb into new gained range.", difficulty: 3, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-050", stem: "A patient demonstrates circumduction gait pattern on the right side during swing phase. What is the likely underlying cause?", options: ["Right hamstring weakness", "Right hip flexor and/or dorsiflexor weakness with spasticity", "Left gluteus medius weakness", "Bilateral ankle plantarflexion contracture"], correctIndex: 1, rationale: "Circumduction gait (leg swings outward in a semicircle during swing) is commonly caused by hip flexor weakness, spasticity, or inability to adequately flex the hip and dorsiflex the ankle.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-051", stem: "The PTA is assessing wound healing. A wound with red, beefy granulation tissue indicates which healing phase?", options: ["Inflammatory phase", "Proliferative phase", "Hemostasis phase", "Maturation/remodeling phase"], correctIndex: 1, rationale: "Red, beefy granulation tissue is characteristic of the proliferative phase, indicating good blood supply and active tissue formation. This is a sign of healthy wound healing.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "pta-052", stem: "Therapeutic ultrasound is CONTRAINDICATED over which area?", options: ["Quadriceps muscle belly", "Lateral epicondyle of the elbow", "Epiphyseal growth plates in children", "Gastrocnemius-soleus complex"], correctIndex: 2, rationale: "Ultrasound is contraindicated over active epiphyseal growth plates in children because the thermal and mechanical effects may damage the growth plate and affect bone development.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-053", stem: "A patient with stroke has difficulty initiating movement on the affected side. Which neurological treatment approach uses handling techniques to normalize tone and facilitate movement?", options: ["McKenzie method", "Williams flexion exercises", "Neurodevelopmental treatment (NDT/Bobath)", "Maitland joint mobilization"], correctIndex: 2, rationale: "NDT/Bobath uses therapeutic handling techniques to inhibit abnormal tone/postures and facilitate normal movement patterns and postural reactions in neurological patients.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-054", stem: "At what age do most children begin to crawl?", options: ["2-3 months", "4-5 months", "8-10 months", "14-16 months"], correctIndex: 2, rationale: "Crawling typically develops between 8-10 months. This milestone requires adequate UE strength, trunk stability, and reciprocal limb coordination.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-055", stem: "A patient has a Stage III pressure injury over the sacrum. What depth of tissue damage does this represent?", options: ["Intact skin with non-blanchable redness", "Partial thickness involving epidermis and dermis", "Full thickness with subcutaneous tissue visible", "Full thickness extending into muscle or bone"], correctIndex: 2, rationale: "Stage III pressure injury: full-thickness skin loss with subcutaneous fat visible. Bone, tendon, and muscle are not exposed (that would be Stage IV).", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "pta-056", stem: "A patient is performing isokinetic exercise on a Biodex machine. What is unique about isokinetic exercise?", options: ["It only allows isometric contractions", "It provides accommodating resistance at a constant speed throughout the ROM", "It uses only body weight for resistance", "It does not involve muscle contraction"], correctIndex: 1, rationale: "Isokinetic exercise provides accommodating resistance at a fixed, pre-set speed. The machine matches resistance to the patient's force output throughout the entire ROM.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-057", stem: "A patient undergoes total knee replacement. What is the ROM goal for knee flexion?", options: ["0-60° flexion", "0-90° flexion", "0-120° flexion", "0-150° flexion"], correctIndex: 2, rationale: "The functional ROM goal after TKR is typically 0° extension to 120° flexion. This allows stair climbing (≈110°), sitting/rising from a chair (≈90°), and most daily activities.", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-058", stem: "Which type of electrical stimulation is used to manage acute and chronic pain by modulating the pain gate mechanism?", options: ["NMES (Neuromuscular Electrical Stimulation)", "TENS (Transcutaneous Electrical Nerve Stimulation)", "IFC (Interferential Current)", "Russian Stimulation"], correctIndex: 1, rationale: "TENS uses low-level electrical current to stimulate sensory nerves, activating the pain gate mechanism (gate control theory) to reduce pain perception.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-059", stem: "A patient has been on bedrest for 2 weeks. Upon standing for the first time, their blood pressure drops from 130/80 to 90/60 mmHg with dizziness. What is this condition?", options: ["Hypertensive crisis", "Orthostatic hypotension", "Cardiac arrest", "Vasovagal response"], correctIndex: 1, rationale: "Orthostatic hypotension is a drop in SBP ≥20 mmHg or DBP ≥10 mmHg when moving from supine/sitting to standing. It is common after prolonged bedrest due to deconditioning of baroreceptor reflexes.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "pta-060", stem: "Which aquatic therapy principle explains why a patient feels lighter in the pool?", options: ["Viscosity", "Hydrostatic pressure", "Buoyancy", "Specific gravity"], correctIndex: 2, rationale: "Buoyancy (Archimedes' principle) creates an upward force that counteracts gravity, reducing apparent body weight. At waist depth, a patient bears approximately 50% of body weight.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-061", stem: "A patient with peripheral neuropathy in the feet has decreased sensation. What is the PRIMARY safety concern?", options: ["Difficulty with fine motor tasks", "Risk of undetected skin injuries and burns", "Increased appetite", "Excessive sweating"], correctIndex: 1, rationale: "Decreased sensation increases risk of undetected injuries, burns, and skin breakdown. The PTA should educate the patient to visually inspect feet daily and avoid extreme temperatures.", difficulty: 1, category: "Safety", topic: "Neurological Rehabilitation" },
  { id: "pta-062", stem: "A patient with McKenzie extension preference for low back pain. What exercise is indicated?", options: ["Williams flexion exercises (posterior pelvic tilt, knee to chest)", "Prone press-ups and standing extension", "Sit-ups and crunches", "Prolonged sitting in flexed posture"], correctIndex: 1, rationale: "McKenzie extension preference indicates symptoms are reduced or centralized with extension. Prone press-ups and standing extension are indicated to reduce symptoms and centralize pain.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-063", stem: "The PTA notices a patient's gait shows excessive knee hyperextension during stance phase. Which muscle group is likely weak?", options: ["Hip abductors", "Quadriceps", "Ankle plantarflexors", "Trunk extensors"], correctIndex: 1, rationale: "Knee hyperextension (genu recurvatum) during stance often compensates for quadriceps weakness. The patient locks the knee in hyperextension for stability instead of using quad control.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-064", stem: "During wound care, which type of debridement involves the use of wet-to-dry dressings?", options: ["Surgical/sharp debridement", "Mechanical debridement", "Enzymatic debridement", "Autolytic debridement"], correctIndex: 1, rationale: "Wet-to-dry dressings are a form of mechanical debridement. The moist gauze adheres to necrotic tissue as it dries; removal pulls off the necrotic tissue with the dressing.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-065", stem: "A patient is performing a 6-Minute Walk Test (6MWT). What does this test assess?", options: ["Maximum sprint speed", "Functional aerobic/cardiovascular endurance", "Unilateral lower extremity strength", "Upper extremity coordination"], correctIndex: 1, rationale: "The 6MWT measures functional cardiovascular endurance by recording the distance walked in 6 minutes at a self-selected pace. It is a reliable measure of submaximal exercise capacity.", difficulty: 1, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-066", stem: "A patient with MS experiences worsening symptoms when body temperature increases. What is this called?", options: ["Babinski sign", "Uhthoff's phenomenon", "Lhermitte's sign", "Romberg sign"], correctIndex: 1, rationale: "Uhthoff's phenomenon is the temporary worsening of MS symptoms with increased body temperature (exercise, hot baths, fever). The PTA should use cooling strategies and avoid overheating.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-067", stem: "Which ankle-foot orthosis (AFO) holds the ankle at 90° to prevent foot drop during gait?", options: ["Knee-ankle-foot orthosis (KAFO)", "Solid/rigid AFO", "Reciprocal gait orthosis (RGO)", "Hip-knee-ankle-foot orthosis (HKAFO)"], correctIndex: 1, rationale: "A solid/rigid AFO maintains the ankle at 90° (neutral dorsiflexion), preventing toe drag during swing phase and providing stability during stance in patients with dorsiflexor weakness.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-068", stem: "A patient is performing body-weight-supported treadmill training (BWSTT) for gait retraining after stroke. What is the primary benefit?", options: ["It eliminates the need for physical therapy", "It allows repetitive practice of the gait cycle with reduced weight-bearing demands", "It replaces all other forms of exercise", "It only works for upper extremity rehabilitation"], correctIndex: 1, rationale: "BWSTT reduces gravitational demands through a harness system, enabling repetitive, task-specific gait practice that promotes motor learning and neural plasticity after stroke.", difficulty: 2, category: "Therapeutic Intervention", topic: "Neurological Rehabilitation" },
  { id: "pta-069", stem: "What is the McMurray test used to assess?", options: ["ACL integrity", "Meniscal tear", "Achilles tendon rupture", "Patellar tendon integrity"], correctIndex: 1, rationale: "The McMurray test assesses meniscal integrity. The examiner flexes the knee, applies rotational force, and extends — a palpable click or pain suggests meniscal damage.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-070", stem: "A patient is performing eccentric quadriceps exercise. What type of contraction occurs?", options: ["The muscle shortens while producing force", "The muscle lengthens while producing force", "The muscle produces force without changing length", "No muscle contraction occurs"], correctIndex: 1, rationale: "Eccentric contraction: the muscle lengthens while producing force. For quadriceps, this occurs during the lowering phase of a squat (controlling knee flexion against gravity).", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-071", stem: "A patient with lower extremity lymphedema. Which intervention is part of complete decongestive therapy (CDT)?", options: ["Application of hot packs to increase blood flow", "Manual lymphatic drainage, compression bandaging, exercise, and skin care", "Vigorous deep tissue massage", "Immersion in hot whirlpool"], correctIndex: 1, rationale: "CDT for lymphedema includes: manual lymphatic drainage, multi-layer compression bandaging, decongestive exercises, skin care, and patient education in self-management.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-072", stem: "What does a positive Trendelenburg test indicate?", options: ["ACL deficiency", "Gluteus medius weakness on the stance leg side", "Hamstring tightness", "Quadriceps weakness"], correctIndex: 1, rationale: "A positive Trendelenburg: the pelvis drops on the unsupported side during single-leg stance, indicating gluteus medius weakness on the stance leg side.", difficulty: 2, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-073", stem: "A patient is being discharged home with crutches. Which surface should the PTA train the patient on BEFORE discharge?", options: ["Only flat indoor surfaces", "Level surfaces, stairs, ramps, and uneven terrain", "Only carpet surfaces", "Escalators and elevators only"], correctIndex: 1, rationale: "Before discharge, the patient must demonstrate safe ambulation on all surfaces they will encounter: level surfaces, stairs (up and down), ramps, and outdoor uneven terrain.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-074", stem: "A newborn demonstrates the Moro reflex. This is an example of which type of reflex?", options: ["Postural reflex", "Primitive reflex", "Equilibrium reaction", "Protective extension response"], correctIndex: 1, rationale: "The Moro (startle) reflex is a primitive reflex present at birth that typically integrates by 4-6 months. Persistence beyond this age may indicate neurological dysfunction.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-075", stem: "Which vital sign change should cause the PTA to STOP exercise immediately?", options: ["Heart rate increase from 72 to 90 bpm during moderate exercise", "Mild perspiration and warmth", "Drop in systolic BP >20 mmHg during exercise (exertional hypotension)", "Slight increase in respiratory rate with exercise"], correctIndex: 2, rationale: "A drop in SBP >20 mmHg during exercise (exertional hypotension) is an indication to stop exercise. It may indicate cardiac dysfunction or inability to maintain adequate cardiac output.", difficulty: 2, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-076", stem: "A patient recovering from TBI is at Rancho Level VI. What does this level indicate?", options: ["No response", "Confused-agitated", "Confused-appropriate — goal-directed behavior with moderate assist", "Purposeful-appropriate — independent"], correctIndex: 2, rationale: "Rancho VI: confused but appropriate. The patient shows goal-directed behavior with external direction, follows simple commands consistently, and demonstrates improved awareness.", difficulty: 3, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-077", stem: "A patient is performing therapeutic exercises in the pool. At waist-depth immersion, approximately what percentage of body weight is supported by buoyancy?", options: ["10%", "25%", "50%", "90%"], correctIndex: 2, rationale: "At waist depth (approximately xiphoid process), buoyancy supports about 50% of body weight. At neck depth, approximately 90% is supported.", difficulty: 2, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-078", stem: "Which documentation format is MOST commonly used by PTAs for treatment notes?", options: ["Narrative essay format", "SOAP note format (Subjective, Objective, Assessment, Plan)", "Social media post format", "Informal email format"], correctIndex: 1, rationale: "SOAP notes are the standard documentation format: Subjective (patient report), Objective (measurable data), Assessment (clinical interpretation), Plan (future treatment direction).", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-079", stem: "A patient with shoulder impingement is performing strengthening exercises. Which exercise targets the rotator cuff muscles?", options: ["Bench press", "Side-lying external rotation with resistance band", "Bicep curls", "Lat pulldowns"], correctIndex: 1, rationale: "Side-lying external rotation specifically targets the infraspinatus and teres minor (external rotators of the rotator cuff). This is a key strengthening exercise for impingement rehabilitation.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-080", stem: "A 6-month-old infant is unable to roll from supine to prone. Is this a developmental concern?", options: ["No, rolling is not expected until 12 months", "Yes, rolling typically develops by 4-6 months and should be assessed", "No, rolling is never expected in infants", "Yes, but intervention should wait until age 3"], correctIndex: 1, rationale: "Rolling from supine to prone typically develops by 4-6 months. A 6-month-old who cannot roll warrants further developmental assessment for potential delays.", difficulty: 2, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-081", stem: "When applying a moist hot pack, how many layers of toweling should be between the hot pack and the patient's skin?", options: ["No toweling needed", "1-2 layers", "6-8 layers of commercial hot pack covers or equivalent", "15-20 layers"], correctIndex: 2, rationale: "6-8 layers of commercial hot pack covers or equivalent toweling protect the skin from burns while allowing therapeutic heat transmission. Always check skin after 5 minutes.", difficulty: 1, category: "Safety", topic: "Therapeutic Exercise" },
  { id: "pta-082", stem: "A patient had an ACL reconstruction. At what timeframe is return to pivoting sports typically allowed?", options: ["2-4 weeks post-surgery", "6-8 weeks post-surgery", "6-9 months post-surgery with functional testing clearance", "2 years post-surgery minimum"], correctIndex: 2, rationale: "Return to pivoting sports after ACL reconstruction typically occurs at 6-9 months, contingent on passing functional testing criteria (hop tests, strength symmetry, proprioception).", difficulty: 2, category: "Patient Care Planning", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-083", stem: "During cryotherapy application, what is the typical duration for ice pack application?", options: ["2-3 minutes", "10-20 minutes", "45-60 minutes", "2 hours continuously"], correctIndex: 1, rationale: "Standard cryotherapy application is 10-20 minutes. This duration achieves therapeutic tissue cooling without risking cold-related tissue damage or frostbite.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-084", stem: "A patient with bilateral above-knee amputations is learning wheelchair mobility. What is an important consideration?", options: ["Standard wheelchair with no modifications", "Anti-tipping wheelchair with rearward-extended axle to prevent backward tipping", "Wheelchair with forward-extended axle", "No wheelchair needed — ambulation with prosthetics only"], correctIndex: 1, rationale: "Bilateral AKA shifts the center of gravity posteriorly. The wheelchair requires a rearward-extended axle and/or anti-tipping devices to prevent backward tipping.", difficulty: 3, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-085", stem: "Which balance assessment tool rates 14 items on a 0-4 scale with a maximum score of 56?", options: ["Timed Up and Go", "Berg Balance Scale", "Tinetti Assessment Tool", "30-Second Chair Stand"], correctIndex: 1, rationale: "The Berg Balance Scale assesses 14 balance tasks scored 0-4 each, maximum score 56. Scores <45 indicate fall risk; <36 indicate high fall risk.", difficulty: 1, category: "Clinical Scenarios", topic: "Geriatric Rehabilitation" },
  { id: "pta-086", stem: "A patient is referred for cardiac rehabilitation Phase II. What characterizes this phase?", options: ["Inpatient acute care rehabilitation", "Outpatient supervised exercise program with ECG monitoring", "Independent unsupervised home exercise", "Pre-surgical conditioning only"], correctIndex: 1, rationale: "Phase II cardiac rehab is a supervised outpatient program with ECG monitoring, typically lasting 6-12 weeks. It progresses exercise intensity while monitoring cardiac response.", difficulty: 2, category: "Patient Care Planning", topic: "Rehabilitation Principles" },
  { id: "pta-087", stem: "The PTA is treating a patient with adhesive capsulitis (frozen shoulder). Which intervention is MOST appropriate?", options: ["Aggressive passive ROM to end range on first visit", "Gradual ROM exercises, joint mobilization, and modalities for pain management", "Complete immobilization for 6 months", "Strengthening exercises only without ROM work"], correctIndex: 1, rationale: "Adhesive capsulitis treatment combines gradual ROM progression, joint mobilization techniques, modalities for pain management, and progressive strengthening as ROM improves.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-088", stem: "A patient with spinal cord injury at T10 level. What functional mobility is expected?", options: ["Independent wheelchair mobility and some functional ambulation with orthotics", "Total dependence for all mobility", "Independent ambulation without devices", "Sip-and-puff wheelchair operation only"], correctIndex: 0, rationale: "T10 SCI preserves full UE function and some trunk stability. The patient can achieve independent wheelchair mobility and may achieve limited community ambulation with KAFOs and crutches.", difficulty: 2, category: "Patient Care Planning", topic: "Neurological Rehabilitation" },
  { id: "pta-089", stem: "Which stretching technique involves a rapid bouncing motion at end range?", options: ["Static stretching", "PNF stretching", "Ballistic stretching", "Dynamic stretching"], correctIndex: 2, rationale: "Ballistic stretching uses rapid bouncing motions at end range. It is generally NOT recommended due to increased risk of muscle injury from activating the stretch reflex.", difficulty: 1, category: "Therapeutic Intervention", topic: "Therapeutic Exercise" },
  { id: "pta-090", stem: "A patient with left CVA is most likely to exhibit which motor deficit?", options: ["Left hemiparesis", "Right hemiparesis", "Bilateral upper extremity weakness only", "Lower extremity weakness only"], correctIndex: 1, rationale: "Left hemisphere stroke causes contralateral (right-sided) motor deficits due to the decussation of motor fibers in the medullary pyramids.", difficulty: 1, category: "Clinical Scenarios", topic: "Neurological Rehabilitation" },
  { id: "pta-091", stem: "When fitting a patient for a cane, the handle height should be at which anatomical landmark?", options: ["Iliac crest", "Greater trochanter of the femur", "Knee joint line", "Ankle malleolus"], correctIndex: 1, rationale: "Cane handle height is measured at the greater trochanter with the patient standing upright. This results in approximately 20-30° elbow flexion for optimal biomechanics.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-092", stem: "A patient with COPD demonstrates pursed-lip breathing. What is the physiological benefit?", options: ["Increases inspiratory volume", "Creates back pressure to keep airways open during exhalation, reducing air trapping", "Strengthens the diaphragm", "Increases oxygen consumption"], correctIndex: 1, rationale: "Pursed-lip breathing creates positive back pressure that keeps small airways open during exhalation, reducing air trapping and dynamic hyperinflation in COPD.", difficulty: 2, category: "Therapeutic Intervention", topic: "Rehabilitation Principles" },
  { id: "pta-093", stem: "The Empty Can test is used to assess which structure?", options: ["ACL", "Supraspinatus tendon/muscle", "Biceps tendon", "Median nerve"], correctIndex: 1, rationale: "The Empty Can (Jobe) test assesses the supraspinatus muscle/tendon. The arm is abducted to 90° in the scapular plane with internal rotation (thumb down); pain or weakness indicates pathology.", difficulty: 2, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-094", stem: "Log rolling technique is used post-operatively for which type of surgery?", options: ["Total knee replacement", "Carpal tunnel release", "Spinal surgery to maintain spinal alignment", "Rotator cuff repair"], correctIndex: 2, rationale: "Log rolling maintains spinal alignment during position changes after spinal surgery. The patient rolls as a unit (shoulders and hips together) to prevent spinal rotation.", difficulty: 1, category: "Safety", topic: "Patient Mobility Techniques" },
  { id: "pta-095", stem: "A patient presents with foot drop. Which assistive device is indicated?", options: ["Knee brace", "Ankle-foot orthosis (AFO)", "Hip abduction brace", "Wrist splint"], correctIndex: 1, rationale: "An AFO holds the ankle in neutral dorsiflexion (90°), preventing the foot from dropping during swing phase and providing stability during stance in patients with dorsiflexor weakness.", difficulty: 1, category: "Patient Care Planning", topic: "Assistive Devices" },
  { id: "pta-096", stem: "A patient is scheduled for NMES (neuromuscular electrical stimulation) to the quadriceps after ACL surgery. What is the primary goal?", options: ["Pain management", "Reducing spasticity", "Facilitating quadriceps contraction and preventing atrophy", "Increasing bone density"], correctIndex: 2, rationale: "NMES after ACL surgery targets the quadriceps to facilitate muscle contraction, prevent disuse atrophy, and improve voluntary muscle recruitment when arthrogenic inhibition is present.", difficulty: 2, category: "Therapeutic Intervention", topic: "Musculoskeletal Rehabilitation" },
  { id: "pta-097", stem: "When should the PTA communicate a change in patient status to the supervising PT?", options: ["Only at the next scheduled meeting", "Immediately when a significant change in patient status is observed", "Only if the patient requests it", "At the end of the billing period"], correctIndex: 1, rationale: "The PTA must communicate significant changes in patient status to the supervising PT immediately. This includes new symptoms, functional decline, adverse responses, or safety concerns.", difficulty: 1, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "pta-098", stem: "A 2-year-old child is unable to jump with both feet off the ground. Is this concerning?", options: ["Yes, jumping should develop by 12 months", "No, jumping with both feet typically develops by 24-36 months", "Yes, the child needs surgery", "No, jumping is not expected until age 6"], correctIndex: 1, rationale: "Jumping with both feet off the ground typically develops between 24-36 months. At 2 years (24 months), the child is at the beginning of the expected range and may not yet have this skill.", difficulty: 1, category: "Clinical Scenarios", topic: "Pediatric Rehabilitation" },
  { id: "pta-099", stem: "Which intervention is CONTRAINDICATED for a patient with deep vein thrombosis (DVT) in the left calf?", options: ["Ankle pumps of the right (unaffected) extremity", "Vigorous massage and exercise of the left (affected) calf", "Upper extremity exercises", "Deep breathing exercises"], correctIndex: 1, rationale: "Vigorous massage and exercise of the affected extremity in DVT is contraindicated due to the risk of dislodging the clot, causing a potentially fatal pulmonary embolism.", difficulty: 2, category: "Safety", topic: "Rehabilitation Principles" },
  { id: "pta-100", stem: "A patient completing PT asks the PTA when their next appointment should be. Who determines the frequency and duration of PT visits?", options: ["The PTA independently decides frequency", "The supervising PT establishes visit frequency as part of the plan of care", "The patient decides their own schedule", "The insurance company solely determines frequency"], correctIndex: 1, rationale: "The supervising PT establishes the frequency, duration, and intensity of physical therapy services as part of the plan of care. The PTA implements treatment within these parameters.", difficulty: 1, category: "Patient Care Planning", topic: "Rehabilitation Principles" }
];
